const handleDownloadPDF = async (booking: Booking) => {
  try {
    const html = getReceiptHTML(booking.guestName, booking.roomNumber, booking.checkIn, booking.checkOut, booking.totalAmount || 0);
    const tempDiv = document.createElement("div");
    tempDiv.id = "temp-receipt-" + booking.id;
    tempDiv.innerHTML = html;
    document.body.appendChild(tempDiv);
    await generatePDFReceipt(tempDiv.id, `Receipt_${booking.roomNumber}_${booking.checkIn}.pdf`);
    document.body.removeChild(tempDiv);
    setActionSuccess("PDF receipt downloaded.");
    setTimeout(() => setActionSuccess(null), 3000);
  } catch (e) {
    console.error(e);
    setActionError("Failed to generate PDF.");
  }
};

const handleManualTransferSubmitted = async () => {
  if (!selectedBookingForPayment) return;
  setPaymentActionLoading(true);

  try {
    if (isSandbox) {
      const rawBookings = localStorage.getItem("innsphere_sandbox_bookings");
      let allBookings = rawBookings ? JSON.parse(rawBookings) : [];
      allBookings = allBookings.map((b: any) => 
        b.id === selectedBookingForPayment.id ? { ...b, paymentStatus: "waiting" } : b
      );
      localStorage.setItem("innsphere_sandbox_bookings", JSON.stringify(allBookings));

      const rawNotifs = localStorage.getItem("innsphere_sandbox_notifications");
      const allNotifs = rawNotifs ? JSON.parse(rawNotifs) : [];
      allNotifs.push({
        id: "notif_payment_" + Date.now(),
        recipientId: "staff_all",
        title: "Payment Transferred",
        message: `Guest ${guestProfile.name} marked payment for Room ${selectedBookingForPayment.roomNumber} as transferred.|||${selectedBookingForPayment.id}`,
        type: "payment",
        status: "unread",
        actionState: "pending"
      });
      localStorage.setItem("innsphere_sandbox_notifications", JSON.stringify(allNotifs));
      window.dispatchEvent(new Event("innsphere_local_update"));
    } else {
      await updateDoc(doc(db, "bookings", selectedBookingForPayment.id), {
        paymentStatus: "waiting",
        updatedAt: serverTimestamp()
      });

      const notifRef = doc(collection(db, "notifications"));
      await setDoc(notifRef, {
        recipientId: "staff_all",
        title: "Payment Transferred",
        message: `Guest ${guestProfile.name} marked payment for Room ${selectedBookingForPayment.roomNumber} as transferred.|||${selectedBookingForPayment.id}`,
        type: "payment",
        status: "unread",
        actionState: "pending",
        createdAt: serverTimestamp()
      });
    }
    setShowPaymentModal(false);
    setActionSuccess("Payment marked as transferred. Awaiting staff confirmation.");
    setTimeout(() => setActionSuccess(null), 4000);
  } catch (err) {
    console.error(err);
    setActionError("Failed to submit transfer notification.");
  } finally {
    setPaymentActionLoading(false);
  }
};

